def is_onto(f, domain, codomain):
    """
    Check if function f: domain → codomain is onto
    """
    images = set(f[x] for x in domain)
    # Function is onto if every codomain element appears in images
    for y in codomain:
        if y not in images:
            return False
    return True

# Example: f: {1,2,3} → {a,b,c}
domain = [1, 2, 3]
codomain = {'a', 'b', 'c'}
f = {1: 'a', 2: 'b', 3: 'a'}  # Not onto - 'c' missing
print(is_onto(f, domain, codomain))  # False

import java.util.*;
import java.util.function.*;

public class FunctionComposition {
    public static void main(String[] args) {
        // Define f: x → x + 2
        Function<Integer, Integer> f = x -> x + 2;

        // Define g: x → x * 3
        Function<Integer, Integer> g = x -> x * 3;

        // Composition g∘f: first apply f, then g
        Function<Integer, Integer> gof = g.compose(f);

        // Test: gof(5) = g(f(5)) = g(7) = 21
        System.out.println("(g∘f)(5) = " + gof.apply(5));

        // Test f∘g
        Function<Integer, Integer> fog = f.compose(g);
        System.out.println("(f∘g)(5) = " + fog.apply(5));

        // Check if f is bijective (for integers, yes)
        System.out.println("f is bijective: " + 
            isBijective(f, -100, 100));
    }

    public static boolean isBijective(Function<Integer, Integer> f, 
                                       int start, int end) {
        Set<Integer> images = new HashSet<>();
        for (int i = start; i <= end; i++) {
            images.add(f.apply(i));
        }
        return images.size() == (end - start + 1);
    }
}
